import {useTranslations} from 'next-intl';
import {getTranslations} from 'next-intl/server';
import {z} from 'zod';
import ZodForm from './ZodForm';

const FormSchema = z.object({
  task: z.string().min(1)
});

type FormInput = z.infer<typeof FormSchema>;

export type FormResult =
  | {
      success: true;
    }
  | {
      success: false;
      errors: {
        formErrors?: Array<string>;
        fieldErrors?: Partial<Record<keyof FormInput, Array<string>>>;
      };
    };

async function submitAction(
  prev: unknown,
  data: FormData
): Promise<FormResult> {
  'use server';

  const values = Object.fromEntries(data.entries());
  const t = await getTranslations('ZodFormExample');

  const result = FormSchema.safeParse(values, {
    error(issue) {
      if (issue.path && issue.path.join('.') === 'task') {
        return t('taskEmpty');
      }
    }
  });

  if (!result.success) {
    return {
      success: false,
      errors: z.flattenError(result.error)
    };
  } else {
    return {
      success: true
    };
  }
}

export default function ZodFormExample() {
  const t = useTranslations('ZodFormExample');

  return (
    <section>
      <h2>Zod form</h2>
      <ZodForm action={submitAction}>
        <input name="task" placeholder={t('task')} type="text" />
      </ZodForm>
    </section>
  );
}

'use client';

import clsx from 'clsx';
import {useParams} from 'next/navigation';
import {Locale} from 'next-intl';
import {ChangeEvent, ReactNode, useTransition} from 'react';
import {usePathname, useRouter} from '@/i18n/navigation';

type Props = {
  children: ReactNode;
  defaultValue: string;
  label: string;
};

export default function LocaleSwitcherSelect({
  children,
  defaultValue,
  label
}: Props) {
  const router = useRouter();
  const [isPending, startTransition] = useTransition();
  const pathname = usePathname();
  const params = useParams();

  function onSelectChange(event: ChangeEvent<HTMLSelectElement>) {
    const nextLocale = event.target.value as Locale;
    startTransition(() => {
      router.replace(
        // @ts-expect-error -- TypeScript will validate that only known `params`
        // are used in combination with a given `pathname`. Since the two will
        // always match for the current route, we can skip runtime checks.
        {pathname, params},
        {locale: nextLocale}
      );
    });
  }

  return (
    <label
      className={clsx(
        'relative text-gray-400',
        isPending && 'transition-opacity [&:disabled]:opacity-30'
      )}
    >
      <p className="sr-only">{label}</p>
      <select
        className="inline-flex appearance-none bg-transparent py-3 pl-2 pr-6"
        defaultValue={defaultValue}
        disabled={isPending}
        onChange={onSelectChange}
      >
        {children}
      </select>
      <span className="pointer-events-none absolute right-2 top-[8px]">⌄</span>
    </label>
  );
}

